/*
Como rodar:
- npm init -y
- npm install express cors
- node server.js
*/

const express = require('express');
const cors = require('cors');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = 3000;
const DB_PATH = path.join(__dirname, 'agendamentos.json');

app.use(cors());
app.use(express.json());

function lerAgendamentos() {
  try {
    if (!fs.existsSync(DB_PATH)) {
      fs.writeFileSync(DB_PATH, '[]', 'utf-8');
    }

    const conteudo = fs.readFileSync(DB_PATH, 'utf-8').trim();
    if (!conteudo) return [];

    const dados = JSON.parse(conteudo);
    return Array.isArray(dados) ? dados : [];
  } catch {
    return [];
  }
}

function salvarAgendamentos(lista) {
  fs.writeFileSync(DB_PATH, JSON.stringify(lista, null, 2), 'utf-8');
}

function isDataValida(data) {
  return /^\d{4}-\d{2}-\d{2}$/.test(data);
}

function isHoraValidaFormato(hora) {
  return /^\d{2}:\d{2}$/.test(hora);
}

function horarioPermitido(hora) {
  const [h, m] = hora.split(':').map(Number);
  if (Number.isNaN(h) || Number.isNaN(m)) return false;
  if (h < 0 || h > 23 || m < 0 || m > 59) return false;

  const minutos = h * 60 + m;
  const inicioManha = 8 * 60;
  const fimManha = 11 * 60;
  const inicioTarde = 13 * 60;
  const fimNoite = 20 * 60;

  const dentroManha = minutos >= inicioManha && minutos <= fimManha;
  const dentroTarde = minutos >= inicioTarde && minutos <= fimNoite;

  return dentroManha || dentroTarde;
}

function ehFimDeSemana(data) {
  const d = new Date(`${data}T00:00:00`);
  if (Number.isNaN(d.getTime())) return true;

  const dia = d.getDay();
  return dia === 0 || dia === 6;
}

app.post('/agendar', (req, res) => {
  const { nome, data, hora } = req.body;

  if (!nome || !data || !hora) {
    return res.status(400).json({ erro: 'Preencha nome, data e hora.' });
  }

  if (typeof nome !== 'string' || typeof data !== 'string' || typeof hora !== 'string') {
    return res.status(400).json({ erro: 'Dados inválidos.' });
  }

  const nomeLimpo = nome.trim();
  if (nomeLimpo.length < 2) {
    return res.status(400).json({ erro: 'Nome do cliente inválido.' });
  }

  if (!isDataValida(data)) {
    return res.status(400).json({ erro: 'Data inválida. Use o formato YYYY-MM-DD.' });
  }

  if (!isHoraValidaFormato(hora)) {
    return res.status(400).json({ erro: 'Hora inválida. Use o formato HH:MM.' });
  }

  if (ehFimDeSemana(data)) {
    return res.status(400).json({ erro: 'Não atendemos sábado e domingo.' });
  }

  if (!horarioPermitido(hora)) {
    return res.status(400).json({ erro: 'Horário fora do funcionamento (08:00-11:00 e 13:00-20:00).' });
  }

  const agendamentos = lerAgendamentos();
  const conflito = agendamentos.find((item) => item.data === data && item.hora === hora);

  if (conflito) {
    return res.status(409).json({ erro: 'Já existe agendamento para este horário.' });
  }

  const novoAgendamento = {
    nome: nomeLimpo,
    data,
    hora,
  };

  agendamentos.push(novoAgendamento);
  salvarAgendamentos(agendamentos);

  return res.status(201).json({
    mensagem: 'Agendamento realizado com sucesso.',
    agendamento: novoAgendamento,
  });
});

app.get('/agendamentos', (_req, res) => {
  const agendamentos = lerAgendamentos();
  return res.json(agendamentos);
});

app.listen(PORT, () => {
  console.log(`Servidor rodando em http://localhost:${PORT}`);
});
